SELECT o.*, ste.site_nm AS site_nm, cd_ot.code_label AS opt_type_cd_nm, cd_oit.code_label AS opt_input_type_cd_nm FROM pd_prod_opt o LEFT JOIN sy_site ste ON ste.site_id = o.site_id LEFT JOIN sy_code cd_ot ON cd_ot.code_grp = 'OPT_TYPE' AND cd_ot.code_value = o.opt_type_cd LEFT JOIN sy_code cd_oit ON cd_oit.code_grp = 'OPT_INPUT_TYPE' AND cd_oit.code_value = o.opt_input_type_cd
ORDER BY o.opt_id ASC ORDER BY o.opt_id DESC ORDER BY o.opt_grp_nm ASC ORDER BY o.opt_grp_nm DESC ORDER BY o.reg_date ASC ORDER BY o.reg_date DESC ORDER BY o.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT o.*, ste.site_nm AS site_nm, cd_ot.code_label AS opt_type_cd_nm, cd_oit.code_label AS opt_input_type_cd_nm FROM pd_prod_opt o LEFT JOIN sy_site ste ON ste.site_id = o.site_id LEFT JOIN sy_code cd_ot ON cd_ot.code_grp = 'OPT_TYPE' AND cd_ot.code_value = o.opt_type_cd LEFT JOIN sy_code cd_oit ON cd_oit.code_grp = 'OPT_INPUT_TYPE' AND cd_oit.code_value = o.opt_input_type_cd
ORDER BY o.opt_id ASC ORDER BY o.opt_id DESC ORDER BY o.opt_grp_nm ASC ORDER BY o.opt_grp_nm DESC ORDER BY o.reg_date ASC ORDER BY o.reg_date DESC ORDER BY o.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

