UPDATE pd_prod_opt
site_id = #{siteId}, prod_id = #{prodId}, opt_grp_nm = #{optGrpNm}, opt_level = #{optLevel}, opt_type_cd = #{optTypeCd}, opt_input_type_cd = #{optInputTypeCd}, sort_ord = #{sortOrd}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE opt_id = #{optId}
